const root = projectRoot;
async function tree(dir, prefix='', depth=0) {
  if (depth > 2) return [];
  let out = [];
  let entries;
  try { entries = await fs.readdir(path.join(root, dir), { withFileTypes: true }); }
  catch { return []; }
  for (const e of entries) {
    if (['node_modules','.git','target','dist','coverage','test-results','.juggler'].includes(e.name)) continue;
    const rel = dir ? dir + '/' + e.name : e.name;
    out.push('  '.repeat(depth) + (e.isDirectory() ? e.name + '/' : e.name));
    if (e.isDirectory()) out.push(...await tree(rel, prefix, depth+1));
  }
  return out;
}
const src = await tree('src');
const tauri = await tree('src-tauri/src');
const capabilities = await glob('src-tauri/capabilities/*').catch(()=>[]);
return { src: src.join('\n'), tauriSrc: tauri.join('\n'), capabilities };

const srcFiles = await glob('src/**/*');
const tauriRs = await glob('src-tauri/src/**/*.rs');
const caps = await glob('src-tauri/capabilities/**/*');
const cargo = await fs.readFile(path.join(projectRoot, 'src-tauri/Cargo.toml'), 'utf8').catch(()=>'(no Cargo.toml)');
return { srcFiles, tauriRs, caps, cargo };

